function Header({ title = 'fromcubes', subtitle = '', children }) {
  return (
    <div className="flex items-center justify-between px-6 py-4">
      <div>
        <h1 className="text-xl font-semibold text-zinc-100 tracking-tight">{title}</h1>
        {subtitle && <p className="text-xs text-zinc-600 mt-0.5">{subtitle}</p>}
      </div>
      <div className="flex items-center gap-2">
        {children || (
          <>
            <span className="inline-block w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
            <span className="text-xs text-zinc-500">streaming</span>
          </>
        )}
      </div>
    </div>
  );
}

function Stat({ label, children }) {
  return (
    <div className="flex items-center gap-3">
      <span className="text-xs text-zinc-500">{label}</span>
      {children}
    </div>
  );
}

function Button({ onClick, children, variant = 'primary', className = '' }) {
  const base = 'px-4 py-2 rounded-lg font-medium transition-colors';
  const variants = {
    primary: 'bg-blue-600 text-white hover:bg-blue-500',
    secondary: 'bg-zinc-700 text-zinc-200 hover:bg-zinc-600',
    danger: 'bg-red-600 text-white hover:bg-red-500'
  };
  return (
    <button
      className={`${base} ${variants[variant] || variants.primary} ${className}`}
      onClick={onClick}
    >{children}</button>
  );
}

function ValueBadge({ label, value, className = '' }) {
  if (value == null) return null;
  return (
    <span className={`text-zinc-600 text-xs ${className}`}>
      {label && <>{label}: </>}{value}
    </span>
  );
}

function Page({ children, className = '' }) {
  return (
    <div className={`min-h-screen bg-zinc-950 text-zinc-100 flex flex-col ${className}`}>
      {children}
    </div>
  );
}
